# solution.py
"""FoodChain - a food delivery and management system.

A single-file, standard-library-only implementation connecting customers,
restaurants, and delivery personnel. The module models the full lifecycle of an
order: browsing restaurants, placing an order, restaurant acceptance, courier
pickup and delivery, feedback, notifications, and adaptive task management.

Design overview
----------------
- Domain entities: User (base) -> Customer / RestaurantOwner / Courier / Admin,
  Restaurant, MenuItem, Menu, Order, OrderItem, Delivery, Feedback, Notification.
- Enums model statuses and roles.
- A FoodChain facade wires services together: AuthService, RestaurantService,
  OrderService, DeliveryService, FeedbackService, NotificationService.
- State machines guard the order and delivery lifecycles; invalid transitions
  raise a domain-specific error.
- Notifications use an observer-style fan-out to per-user inboxes.
- Security uses salted SHA-256 password hashing, session tokens, and a small
  XOR+base64 "transport" cipher to simulate encrypted transmission.

All source and output is ASCII-only to avoid Windows cp1252 issues.
"""

from __future__ import annotations

import base64
import hashlib
import hmac
import os
import sys
import uuid
from dataclasses import dataclass, field
from enum import Enum
from typing import Dict, Iterable, List, Optional, Tuple


# ---------------------------------------------------------------------------
# Exceptions
# ---------------------------------------------------------------------------
class FoodChainError(Exception):
    """Base class for all FoodChain domain errors."""


class AuthenticationError(FoodChainError):
    """Raised when credentials or session tokens are invalid."""


class AuthorizationError(FoodChainError):
    """Raised when an authenticated user lacks permission for an action."""


class NotFoundError(FoodChainError):
    """Raised when a referenced entity does not exist."""


class ValidationError(FoodChainError):
    """Raised when input fails validation."""


class InvalidStateTransitionError(FoodChainError):
    """Raised when a lifecycle transition is not allowed."""


# ---------------------------------------------------------------------------
# Enums
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """The role a user plays in the system."""

    CUSTOMER = "customer"
    RESTAURANT = "restaurant"
    COURIER = "courier"
    ADMIN = "admin"


class OrderType(Enum):
    """Whether the order is delivered or picked up."""

    DELIVERY = "delivery"
    PICKUP = "pickup"


class OrderStatus(Enum):
    """Lifecycle states for an order."""

    PLACED = "placed"
    ACCEPTED = "accepted"
    REJECTED = "rejected"
    PREPARING = "preparing"
    READY = "ready"
    PICKED_UP = "picked_up"
    OUT_FOR_DELIVERY = "out_for_delivery"
    DELIVERED = "delivered"
    CANCELLED = "cancelled"


class DeliveryStatus(Enum):
    """Lifecycle states for a delivery job."""

    UNASSIGNED = "unassigned"
    ASSIGNED = "assigned"
    PICKED_UP = "picked_up"
    EN_ROUTE = "en_route"
    DELIVERED = "delivered"
    FAILED = "failed"


class Priority(Enum):
    """Order priority used by adaptive task management."""

    LOW = 1
    NORMAL = 2
    HIGH = 3
    URGENT = 4


# Valid order state transitions.
_ORDER_TRANSITIONS: Dict[OrderStatus, Tuple[OrderStatus, ...]] = {
    OrderStatus.PLACED: (OrderStatus.ACCEPTED, OrderStatus.REJECTED, OrderStatus.CANCELLED),
    OrderStatus.ACCEPTED: (OrderStatus.PREPARING, OrderStatus.CANCELLED),
    OrderStatus.PREPARING: (OrderStatus.READY, OrderStatus.CANCELLED),
    OrderStatus.READY: (OrderStatus.PICKED_UP, OrderStatus.DELIVERED, OrderStatus.CANCELLED),
    OrderStatus.PICKED_UP: (OrderStatus.OUT_FOR_DELIVERY, OrderStatus.DELIVERED),
    OrderStatus.OUT_FOR_DELIVERY: (OrderStatus.DELIVERED,),
    OrderStatus.REJECTED: (),
    OrderStatus.DELIVERED: (),
    OrderStatus.CANCELLED: (),
}

# Valid delivery state transitions.
_DELIVERY_TRANSITIONS: Dict[DeliveryStatus, Tuple[DeliveryStatus, ...]] = {
    DeliveryStatus.UNASSIGNED: (DeliveryStatus.ASSIGNED,),
    DeliveryStatus.ASSIGNED: (DeliveryStatus.PICKED_UP, DeliveryStatus.FAILED),
    DeliveryStatus.PICKED_UP: (DeliveryStatus.EN_ROUTE, DeliveryStatus.FAILED),
    DeliveryStatus.EN_ROUTE: (DeliveryStatus.DELIVERED, DeliveryStatus.FAILED),
    DeliveryStatus.DELIVERED: (),
    DeliveryStatus.FAILED: (),
}


# ---------------------------------------------------------------------------
# Security helpers
# ---------------------------------------------------------------------------
class SecurityUtil:
    """Standard-library-only security helpers.

    Provides salted SHA-256 password hashing and a reversible XOR+base64
    cipher used to simulate encrypted transport. No third-party crypto is used.
    """

    @staticmethod
    def hash_password(password: str, salt: Optional[str] = None) -> str:
        """Return a salted SHA-256 hash encoded as ``salt$hexdigest``."""
        if not isinstance(password, str) or password == "":
            raise ValidationError("Password must be a non-empty string.")
        if salt is None:
            salt = os.urandom(16).hex()
        digest = hashlib.sha256((salt + password).encode("utf-8")).hexdigest()
        return salt + "$" + digest

    @staticmethod
    def verify_password(password: str, stored: str) -> bool:
        """Verify a plaintext password against a stored ``salt$hexdigest``."""
        if not stored or "$" not in stored:
            return False
        salt, _digest = stored.split("$", 1)
        candidate = SecurityUtil.hash_password(password, salt)
        return hmac.compare_digest(candidate, stored)

    @staticmethod
    def encrypt(plaintext: str, key: str) -> str:
        """Reversible XOR cipher with base64 encoding (simulated transport)."""
        if not isinstance(plaintext, str):
            raise ValidationError("Plaintext must be a string.")
        if not key:
            raise ValidationError("Encryption key must be non-empty.")
        key_bytes = key.encode("utf-8")
        data = plaintext.encode("utf-8")
        xored = bytes(b ^ key_bytes[i % len(key_bytes)] for i, b in enumerate(data))
        return base64.b64encode(xored).decode("ascii")

    @staticmethod
    def decrypt(ciphertext: str, key: str) -> str:
        """Inverse of :meth:`encrypt`."""
        if not key:
            raise ValidationError("Encryption key must be non-empty.")
        key_bytes = key.encode("utf-8")
        try:
            xored = base64.b64decode(ciphertext.encode("ascii"))
        except Exception as exc:  # noqa: BLE001 - normalize to domain error
            raise ValidationError("Invalid ciphertext.") from exc
        data = bytes(b ^ key_bytes[i % len(key_bytes)] for i, b in enumerate(xored))
        return data.decode("utf-8")


# ---------------------------------------------------------------------------
# Domain entities
# ---------------------------------------------------------------------------
def _new_id(prefix: str) -> str:
    """Generate a short, readable unique id with a typed prefix."""
    return prefix + "-" + uuid.uuid4().hex[:8]


@dataclass
class User:
    """Base user with a role and salted password hash."""

    username: str
    role: UserRole
    password_hash: str
    user_id: str = field(default_factory=lambda: _new_id("usr"))
    display_name: str = ""

    def __post_init__(self) -> None:
        if not self.display_name:
            self.display_name = self.username


@dataclass
class Customer(User):
    """A customer who can browse restaurants and place orders."""

    location: float = 0.0  # 1-D coordinate (km) used for distance calc.


@dataclass
class RestaurantOwner(User):
    """Owner/operator account that manages a restaurant."""

    restaurant_id: Optional[str] = None


@dataclass
class Courier(User):
    """Delivery person who picks up and delivers orders."""

    location: float = 0.0
    active_jobs: int = 0
    available: bool = True


@dataclass
class Admin(User):
    """Administrative account (reserved for system operations)."""


@dataclass
class MenuItem:
    """A single purchasable item on a restaurant menu."""

    name: str
    price: float
    available: bool = True
    item_id: str = field(default_factory=lambda: _new_id("itm"))


@dataclass
class Menu:
    """A collection of menu items for a restaurant."""

    items: Dict[str, MenuItem] = field(default_factory=dict)

    def add_item(self, item: MenuItem) -> MenuItem:
        self.items[item.item_id] = item
        return item

    def get(self, item_id: str) -> MenuItem:
        item = self.items.get(item_id)
        if item is None:
            raise NotFoundError("Menu item '" + item_id + "' not found.")
        return item

    def list_available(self) -> List[MenuItem]:
        return [i for i in self.items.values() if i.available]


@dataclass
class Restaurant:
    """A restaurant with a location and a menu."""

    name: str
    owner_id: str
    location: float = 0.0
    menu: Menu = field(default_factory=Menu)
    is_open: bool = True
    restaurant_id: str = field(default_factory=lambda: _new_id("rst"))


@dataclass
class OrderItem:
    """A line item within an order: a menu item and a quantity."""

    item_id: str
    name: str
    unit_price: float
    quantity: int

    @property
    def subtotal(self) -> float:
        return round(self.unit_price * self.quantity, 2)


@dataclass
class Order:
    """A customer order with a lifecycle state machine."""

    customer_id: str
    restaurant_id: str
    order_type: OrderType
    items: List[OrderItem] = field(default_factory=list)
    status: OrderStatus = OrderStatus.PLACED
    priority: Priority = Priority.NORMAL
    eta_minutes: Optional[float] = None
    history: List[OrderStatus] = field(default_factory=list)
    order_id: str = field(default_factory=lambda: _new_id("ord"))

    def __post_init__(self) -> None:
        if not self.history:
            self.history.append(self.status)

    @property
    def total(self) -> float:
        return round(sum(i.subtotal for i in self.items), 2)

    def can_transition(self, target: OrderStatus) -> bool:
        return target in _ORDER_TRANSITIONS.get(self.status, ())

    def transition(self, target: OrderStatus) -> None:
        """Move to ``target`` if the transition is valid."""
        if not self.can_transition(target):
            raise InvalidStateTransitionError(
                "Order " + self.order_id + " cannot move from "
                + self.status.value + " to " + target.value + "."
            )
        self.status = target
        self.history.append(target)


@dataclass
class Delivery:
    """A delivery job tied to an order, with its own lifecycle."""

    order_id: str
    pickup_location: float
    dropoff_location: float
    courier_id: Optional[str] = None
    status: DeliveryStatus = DeliveryStatus.UNASSIGNED
    route: List[float] = field(default_factory=list)
    eta_minutes: Optional[float] = None
    delivery_id: str = field(default_factory=lambda: _new_id("dlv"))

    def can_transition(self, target: DeliveryStatus) -> bool:
        return target in _DELIVERY_TRANSITIONS.get(self.status, ())

    def transition(self, target: DeliveryStatus) -> None:
        if not self.can_transition(target):
            raise InvalidStateTransitionError(
                "Delivery " + self.delivery_id + " cannot move from "
                + self.status.value + " to " + target.value + "."
            )
        self.status = target


@dataclass
class Feedback:
    """Customer feedback rating a restaurant and (optionally) a courier."""

    order_id: str
    customer_id: str
    restaurant_id: str
    restaurant_rating: int
    courier_id: Optional[str] = None
    courier_rating: Optional[int] = None
    comment: str = ""
    feedback_id: str = field(default_factory=lambda: _new_id("fbk"))


@dataclass
class Notification:
    """A single message delivered to a user's inbox."""

    user_id: str
    message: str
    order_id: Optional[str] = None
    seq: int = 0
    notification_id: str = field(default_factory=lambda: _new_id("ntf"))


# ---------------------------------------------------------------------------
# Services
# ---------------------------------------------------------------------------
class NotificationService:
    """Observer-style notification fan-out with per-user inboxes."""

    def __init__(self) -> None:
        self._inboxes: Dict[str, List[Notification]] = {}
        self._seq = 0

    def notify(self, user_id: str, message: str, order_id: Optional[str] = None) -> Notification:
        """Append a notification to ``user_id``'s inbox and return it."""
        if not user_id:
            raise ValidationError("user_id is required for notification.")
        self._seq += 1
        note = Notification(user_id=user_id, message=message, order_id=order_id, seq=self._seq)
        self._inboxes.setdefault(user_id, []).append(note)
        return note

    def notify_many(self, user_ids: Iterable[str], message: str, order_id: Optional[str] = None) -> None:
        """Send the same message to several users (deduplicated)."""
        seen = set()
        for uid in user_ids:
            if uid and uid not in seen:
                seen.add(uid)
                self.notify(uid, message, order_id)

    def inbox(self, user_id: str) -> List[Notification]:
        """Return a defensive copy of a user's notifications."""
        return list(self._inboxes.get(user_id, []))


class AuthService:
    """Registration, login, session tokens, and authorization."""

    def __init__(self) -> None:
        self._users_by_id: Dict[str, User] = {}
        self._users_by_name: Dict[str, str] = {}
        self._tokens: Dict[str, str] = {}  # token -> user_id

    def register(
        self,
        username: str,
        password: str,
        role: UserRole,
        display_name: str = "",
        location: float = 0.0,
    ) -> User:
        """Create a user with a salted hashed password."""
        if not username or not username.strip():
            raise ValidationError("Username must be non-empty.")
        if username in self._users_by_name:
            raise ValidationError("Username '" + username + "' is already taken.")
        if not isinstance(role, UserRole):
            raise ValidationError("Invalid role.")
        pw_hash = SecurityUtil.hash_password(password)

        if role is UserRole.CUSTOMER:
            user: User = Customer(username, role, pw_hash, display_name=display_name, location=location)
        elif role is UserRole.RESTAURANT:
            user = RestaurantOwner(username, role, pw_hash, display_name=display_name)
        elif role is UserRole.COURIER:
            user = Courier(username, role, pw_hash, display_name=display_name, location=location)
        else:
            user = Admin(username, role, pw_hash, display_name=display_name)

        self._users_by_id[user.user_id] = user
        self._users_by_name[username] = user.user_id
        return user

    def login(self, username: str, password: str) -> str:
        """Verify credentials and return a session token."""
        uid = self._users_by_name.get(username)
        if uid is None:
            raise AuthenticationError("Unknown username or password.")
        user = self._users_by_id[uid]
        if not SecurityUtil.verify_password(password, user.password_hash):
            raise AuthenticationError("Unknown username or password.")
        token = uuid.uuid4().hex
        self._tokens[token] = uid
        return token

    def logout(self, token: str) -> None:
        self._tokens.pop(token, None)

    def authenticate(self, token: str) -> User:
        """Resolve a token to a user, or raise AuthenticationError."""
        uid = self._tokens.get(token)
        if uid is None:
            raise AuthenticationError("Invalid or expired session token.")
        return self._users_by_id[uid]

    def require_role(self, token: str, role: UserRole) -> User:
        """Authenticate and assert the user has ``role``."""
        user = self.authenticate(token)
        if user.role is not role:
            raise AuthorizationError(
                "Operation requires role " + role.value + " but user is " + user.role.value + "."
            )
        return user

    def get_user(self, user_id: str) -> User:
        user = self._users_by_id.get(user_id)
        if user is None:
            raise NotFoundError("User '" + user_id + "' not found.")
        return user


class RestaurantService:
    """Create restaurants, manage menus, and support browsing."""

    def __init__(self, auth: AuthService) -> None:
        self._auth = auth
        self._restaurants: Dict[str, Restaurant] = {}

    def create_restaurant(self, owner: RestaurantOwner, name: str, location: float = 0.0) -> Restaurant:
        if not name or not name.strip():
            raise ValidationError("Restaurant name must be non-empty.")
        restaurant = Restaurant(name=name, owner_id=owner.user_id, location=location)
        self._restaurants[restaurant.restaurant_id] = restaurant
        owner.restaurant_id = restaurant.restaurant_id
        return restaurant

    def get(self, restaurant_id: str) -> Restaurant:
        restaurant = self._restaurants.get(restaurant_id)
        if restaurant is None:
            raise NotFoundError("Restaurant '" + restaurant_id + "' not found.")
        return restaurant

    def add_menu_item(self, owner: RestaurantOwner, restaurant_id: str, name: str, price: float) -> MenuItem:
        restaurant = self.get(restaurant_id)
        if restaurant.owner_id != owner.user_id:
            raise AuthorizationError("Only the owner can modify this restaurant menu.")
        if price < 0:
            raise ValidationError("Price must be non-negative.")
        return restaurant.menu.add_item(MenuItem(name=name, price=round(float(price), 2)))

    def browse_nearby(self, location: float, radius: float = 10.0) -> List[Restaurant]:
        """Return open restaurants within ``radius`` km, nearest first."""
        if radius < 0:
            raise ValidationError("Radius must be non-negative.")
        nearby = [
            (abs(r.location - location), r)
            for r in self._restaurants.values()
            if r.is_open
        ]
        nearby = [(d, r) for d, r in nearby if d <= radius]
        nearby.sort(key=lambda pair: pair[0])
        return [r for _, r in nearby]

    def view_menu(self, restaurant_id: str) -> List[MenuItem]:
        return self.get(restaurant_id).menu.list_available()


class DeliveryService:
    """Assign couriers, run delivery lifecycle, and adapt routes/ETAs."""

    SPEED_KM_PER_MIN = 0.5  # ~30 km/h average courier speed.

    def __init__(self, auth: AuthService, notifications: NotificationService) -> None:
        self._auth = auth
        self._notifications = notifications
        self._deliveries: Dict[str, Delivery] = {}
        self._by_order: Dict[str, str] = {}
        self._couriers: Dict[str, Courier] = {}

    def register_courier(self, courier: Courier) -> None:
        self._couriers[courier.user_id] = courier

    def get(self, delivery_id: str) -> Delivery:
        delivery = self._deliveries.get(delivery_id)
        if delivery is None:
            raise NotFoundError("Delivery '" + delivery_id + "' not found.")
        return delivery

    def get_by_order(self, order_id: str) -> Delivery:
        did = self._by_order.get(order_id)
        if did is None:
            raise NotFoundError("No delivery for order '" + order_id + "'.")
        return self._deliveries[did]

    def estimate_eta(self, distance: float, courier_load: int = 0) -> float:
        """ETA in minutes from distance plus a load-based penalty."""
        base = abs(distance) / self.SPEED_KM_PER_MIN
        load_penalty = courier_load * 5.0
        return round(base + load_penalty + 5.0, 1)  # +5 min prep/handoff buffer

    def create_delivery(self, order: Order, pickup: float, dropoff: float) -> Delivery:
        delivery = Delivery(order_id=order.order_id, pickup_location=pickup, dropoff_location=dropoff)
        delivery.route = [pickup, dropoff]
        self._deliveries[delivery.delivery_id] = delivery
        self._by_order[order.order_id] = delivery.delivery_id
        return delivery

    def assign_best_courier(self, delivery: Delivery) -> Courier:
        """Pick the available courier closest to pickup with the lowest load."""
        candidates = [c for c in self._couriers.values() if c.available]
        if not candidates:
            raise NotFoundError("No available couriers.")
        candidates.sort(key=lambda c: (c.active_jobs, abs(c.location - delivery.pickup_location)))
        courier = candidates[0]
        delivery.transition(DeliveryStatus.ASSIGNED)
        delivery.courier_id = courier.user_id
        courier.active_jobs += 1
        distance = abs(delivery.dropoff_location - delivery.pickup_location)
        delivery.eta_minutes = self.estimate_eta(distance, courier.active_jobs - 1)
        return courier

    def pick_up(self, courier: Courier, delivery_id: str) -> Delivery:
        delivery = self.get(delivery_id)
        if delivery.courier_id != courier.user_id:
            raise AuthorizationError("This delivery is assigned to another courier.")
        delivery.transition(DeliveryStatus.PICKED_UP)
        return delivery

    def start_route(self, courier: Courier, delivery_id: str) -> Delivery:
        delivery = self.get(delivery_id)
        if delivery.courier_id != courier.user_id:
            raise AuthorizationError("This delivery is assigned to another courier.")
        delivery.transition(DeliveryStatus.EN_ROUTE)
        return delivery

    def complete(self, courier: Courier, delivery_id: str) -> Delivery:
        delivery = self.get(delivery_id)
        if delivery.courier_id != courier.user_id:
            raise AuthorizationError("This delivery is assigned to another courier.")
        delivery.transition(DeliveryStatus.DELIVERED)
        delivery.eta_minutes = 0.0
        if courier.active_jobs > 0:
            courier.active_jobs -= 1
        return delivery

    def adjust_route(self, delivery_id: str, waypoints: List[float]) -> Delivery:
        """Adaptive re-routing: replace the route and recompute ETA."""
        delivery = self.get(delivery_id)
        if not waypoints:
            raise ValidationError("Route must contain at least one waypoint.")
        delivery.route = list(waypoints)
        total = 0.0
        prev = delivery.pickup_location
        for wp in waypoints:
            total += abs(wp - prev)
            prev = wp
        load = 0
        if delivery.courier_id:
            courier = self._couriers.get(delivery.courier_id)
            if courier is not None:
                load = courier.active_jobs - 1
        delivery.eta_minutes = self.estimate_eta(total, max(load, 0))
        return delivery


class FeedbackService:
    """Store ratings and compute running averages per restaurant/courier."""

    def __init__(self) -> None:
        self._feedback: Dict[str, Feedback] = {}
        # Running (sum, count) aggregates give O(1) average reads.
        self._restaurant_ratings: Dict[str, Tuple[int, int]] = {}
        self._courier_ratings: Dict[str, Tuple[int, int]] = {}

    @staticmethod
    def _validate_rating(value: int, label: str) -> int:
        if not isinstance(value, int) or value < 1 or value > 5:
            raise ValidationError(label + " rating must be an integer 1-5.")
        return value

    def submit(
        self,
        order: Order,
        restaurant_rating: int,
        courier_id: Optional[str] = None,
        courier_rating: Optional[int] = None,
        comment: str = "",
    ) -> Feedback:
        if order.status is not OrderStatus.DELIVERED:
            raise ValidationError("Feedback can only be left for delivered orders.")
        self._validate_rating(restaurant_rating, "Restaurant")
        if courier_rating is not None:
            self._validate_rating(courier_rating, "Courier")

        feedback = Feedback(
            order_id=order.order_id,
            customer_id=order.customer_id,
            restaurant_id=order.restaurant_id,
            restaurant_rating=restaurant_rating,
            courier_id=courier_id,
            courier_rating=courier_rating,
            comment=comment,
        )
        self._feedback[feedback.feedback_id] = feedback
        r_sum, r_count = self._restaurant_ratings.get(order.restaurant_id, (0, 0))
        self._restaurant_ratings[order.restaurant_id] = (r_sum + restaurant_rating, r_count + 1)
        if courier_id and courier_rating is not None:
            c_sum, c_count = self._courier_ratings.get(courier_id, (0, 0))
            self._courier_ratings[courier_id] = (c_sum + courier_rating, c_count + 1)
        return feedback

    @staticmethod
    def _average(aggregate: Optional[Tuple[int, int]]) -> Optional[float]:
        if not aggregate or aggregate[1] == 0:
            return None
        total, count = aggregate
        return round(total / count, 2)

    def restaurant_score(self, restaurant_id: str) -> Optional[float]:
        return self._average(self._restaurant_ratings.get(restaurant_id))

    def courier_score(self, courier_id: str) -> Optional[float]:
        return self._average(self._courier_ratings.get(courier_id))


class OrderService:
    """Place orders and drive the order lifecycle with notifications."""

    def __init__(
        self,
        auth: AuthService,
        restaurants: RestaurantService,
        deliveries: DeliveryService,
        notifications: NotificationService,
    ) -> None:
        self._auth = auth
        self._restaurants = restaurants
        self._deliveries = deliveries
        self._notifications = notifications
        self._orders: Dict[str, Order] = {}

    def get(self, order_id: str) -> Order:
        order = self._orders.get(order_id)
        if order is None:
            raise NotFoundError("Order '" + order_id + "' not found.")
        return order

    def _parties(self, order: Order) -> List[str]:
        """All user_ids that should hear about this order's events."""
        ids = [order.customer_id]
        restaurant = self._restaurants.get(order.restaurant_id)
        ids.append(restaurant.owner_id)
        try:
            delivery = self._deliveries.get_by_order(order.order_id)
            if delivery.courier_id:
                ids.append(delivery.courier_id)
        except NotFoundError:
            pass
        return ids

    def _broadcast(self, order: Order, message: str) -> None:
        self._notifications.notify_many(self._parties(order), message, order.order_id)

    def place_order(
        self,
        customer: Customer,
        restaurant_id: str,
        item_quantities: Dict[str, int],
        order_type: OrderType,
        priority: Priority = Priority.NORMAL,
    ) -> Order:
        """Create an order from a map of menu item_id -> quantity."""
        restaurant = self._restaurants.get(restaurant_id)
        if not restaurant.is_open:
            raise ValidationError("Restaurant is currently closed.")
        if not item_quantities:
            raise ValidationError("Order must contain at least one item.")

        order_items: List[OrderItem] = []
        for item_id, qty in item_quantities.items():
            if qty <= 0:
                raise ValidationError("Quantity for '" + item_id + "' must be positive.")
            menu_item = restaurant.menu.get(item_id)
            if not menu_item.available:
                raise ValidationError("Item '" + menu_item.name + "' is unavailable.")
            order_items.append(
                OrderItem(menu_item.item_id, menu_item.name, menu_item.price, qty)
            )

        order = Order(
            customer_id=customer.user_id,
            restaurant_id=restaurant_id,
            order_type=order_type,
            items=order_items,
            priority=priority,
        )
        self._orders[order.order_id] = order

        if order_type is OrderType.DELIVERY:
            self._deliveries.create_delivery(order, restaurant.location, customer.location)

        self._broadcast(order, "Order " + order.order_id + " placed (total " + str(order.total) + ").")
        return order

    def accept_order(self, owner: RestaurantOwner, order_id: str) -> Order:
        order = self.get(order_id)
        self._assert_owner(owner, order)
        order.transition(OrderStatus.ACCEPTED)
        self._broadcast(order, "Order " + order.order_id + " accepted by the restaurant.")
        return order

    def reject_order(self, owner: RestaurantOwner, order_id: str, reason: str = "") -> Order:
        order = self.get(order_id)
        self._assert_owner(owner, order)
        order.transition(OrderStatus.REJECTED)
        msg = "Order " + order.order_id + " rejected by the restaurant."
        if reason:
            msg += " Reason: " + reason
        self._broadcast(order, msg)
        return order

    def modify_order_quantity(self, owner: RestaurantOwner, order_id: str, item_id: str, new_qty: int) -> Order:
        """Restaurant adjusts an item quantity based on availability."""
        order = self.get(order_id)
        self._assert_owner(owner, order)
        if order.status not in (OrderStatus.PLACED, OrderStatus.ACCEPTED):
            raise ValidationError("Order can only be modified before preparation.")
        if new_qty < 0:
            raise ValidationError("Quantity must be non-negative.")
        target = None
        for oi in order.items:
            if oi.item_id == item_id:
                target = oi
                break
        if target is None:
            raise NotFoundError("Item '" + item_id + "' is not in this order.")
        if new_qty == 0:
            order.items.remove(target)
        else:
            target.quantity = new_qty
        if not order.items:
            raise ValidationError("Order cannot be left empty; cancel it instead.")
        self._broadcast(order, "Order " + order.order_id + " modified (new total " + str(order.total) + ").")
        return order

    def start_preparing(self, owner: RestaurantOwner, order_id: str) -> Order:
        order = self.get(order_id)
        self._assert_owner(owner, order)
        order.transition(OrderStatus.PREPARING)
        self._broadcast(order, "Order " + order.order_id + " is being prepared.")
        return order

    def mark_ready(self, owner: RestaurantOwner, order_id: str) -> Order:
        order = self.get(order_id)
        self._assert_owner(owner, order)
        order.transition(OrderStatus.READY)
        self._broadcast(order, "Order " + order.order_id + " is ready.")
        if order.order_type is OrderType.DELIVERY:
            delivery = self._deliveries.get_by_order(order.order_id)
            courier = self._deliveries.assign_best_courier(delivery)
            order.eta_minutes = delivery.eta_minutes
            self._broadcast(
                order,
                "Courier " + courier.display_name + " assigned. ETA "
                + str(delivery.eta_minutes) + " min.",
            )
        return order

    def courier_pickup(self, courier: Courier, order_id: str) -> Order:
        order = self.get(order_id)
        delivery = self._deliveries.get_by_order(order_id)
        self._deliveries.pick_up(courier, delivery.delivery_id)
        order.transition(OrderStatus.PICKED_UP)
        self._broadcast(order, "Order " + order.order_id + " picked up by courier.")
        return order

    def courier_out_for_delivery(self, courier: Courier, order_id: str) -> Order:
        order = self.get(order_id)
        delivery = self._deliveries.get_by_order(order_id)
        self._deliveries.start_route(courier, delivery.delivery_id)
        order.transition(OrderStatus.OUT_FOR_DELIVERY)
        self._broadcast(order, "Order " + order.order_id + " is out for delivery.")
        return order

    def courier_deliver(self, courier: Courier, order_id: str) -> Order:
        order = self.get(order_id)
        delivery = self._deliveries.get_by_order(order_id)
        self._deliveries.complete(courier, delivery.delivery_id)
        order.transition(OrderStatus.DELIVERED)
        self._broadcast(order, "Order " + order.order_id + " delivered. Enjoy!")
        return order

    def customer_pickup(self, customer: Customer, order_id: str) -> Order:
        """Mark a PICKUP-type order as collected by the customer."""
        order = self.get(order_id)
        if order.customer_id != customer.user_id:
            raise AuthorizationError("Only the ordering customer can collect this order.")
        if order.order_type is not OrderType.PICKUP:
            raise ValidationError("This order is for delivery, not pickup.")
        order.transition(OrderStatus.DELIVERED)
        self._broadcast(order, "Order " + order.order_id + " collected by customer.")
        return order

    def cancel_order(self, customer: Customer, order_id: str) -> Order:
        order = self.get(order_id)
        if order.customer_id != customer.user_id:
            raise AuthorizationError("Only the ordering customer can cancel this order.")
        order.transition(OrderStatus.CANCELLED)
        self._broadcast(order, "Order " + order.order_id + " cancelled by customer.")
        return order

    def set_priority(self, order_id: str, priority: Priority) -> Order:
        """Adaptive management: reprioritize an in-flight order."""
        order = self.get(order_id)
        if not isinstance(priority, Priority):
            raise ValidationError("Invalid priority.")
        order.priority = priority
        self._broadcast(order, "Order " + order.order_id + " priority set to " + priority.name + ".")
        return order

    def _assert_owner(self, owner: RestaurantOwner, order: Order) -> None:
        restaurant = self._restaurants.get(order.restaurant_id)
        if restaurant.owner_id != owner.user_id:
            raise AuthorizationError("Only the restaurant owner can manage this order.")


# ---------------------------------------------------------------------------
# Facade
# ---------------------------------------------------------------------------
class FoodChain:
    """Central facade wiring all services together."""

    TRANSPORT_KEY = "foodchain-secret-key"

    def __init__(self) -> None:
        self.auth = AuthService()
        self.notifications = NotificationService()
        self.restaurants = RestaurantService(self.auth)
        self.deliveries = DeliveryService(self.auth, self.notifications)
        self.feedback = FeedbackService()
        self.orders = OrderService(self.auth, self.restaurants, self.deliveries, self.notifications)

    # Security/transport convenience helpers ------------------------------
    def secure_send(self, payload: str) -> str:
        """Simulate encrypted transmission of a payload."""
        return SecurityUtil.encrypt(payload, self.TRANSPORT_KEY)

    def secure_receive(self, ciphertext: str) -> str:
        return SecurityUtil.decrypt(ciphertext, self.TRANSPORT_KEY)

    # Registration helpers ------------------------------------------------
    def register_customer(self, username: str, password: str, location: float = 0.0) -> Customer:
        user = self.auth.register(username, password, UserRole.CUSTOMER, location=location)
        return user  # type: ignore[return-value]

    def register_owner(self, username: str, password: str) -> RestaurantOwner:
        return self.auth.register(username, password, UserRole.RESTAURANT)  # type: ignore[return-value]

    def register_courier(self, username: str, password: str, location: float = 0.0) -> Courier:
        courier = self.auth.register(username, password, UserRole.COURIER, location=location)
        self.deliveries.register_courier(courier)  # type: ignore[arg-type]
        return courier  # type: ignore[return-value]


# ---------------------------------------------------------------------------
# Demo
# ---------------------------------------------------------------------------
def _print_inbox(system: FoodChain, user: User) -> None:
    print("  Inbox for " + user.display_name + " (" + user.role.value + "):")
    for note in system.notifications.inbox(user.user_id):
        print("    [" + str(note.seq).rjust(2) + "] " + note.message)


def main() -> None:
    """Exercise the full FoodChain flow end-to-end."""
    system = FoodChain()
    print("=== FoodChain end-to-end demo ===\n")

    # 1) Security: register users with hashed passwords, then log in.
    print("-- Registration & secure login --")
    customer = system.register_customer("alice", "s3cret!", location=2.0)
    owner = system.register_owner("bobs_diner", "ownerpass")
    courier = system.register_courier("carl", "drivepass", location=0.5)
    print("  Registered customer, owner, courier (passwords are salted-hashed).")
    print("  Stored hash sample (customer): " + customer.password_hash[:24] + "...")

    cust_token = system.auth.login("alice", "s3cret!")
    owner_token = system.auth.login("bobs_diner", "ownerpass")
    courier_token = system.auth.login("carl", "drivepass")
    print("  Issued session tokens for all three users.")

    try:
        system.auth.login("alice", "wrong")
    except AuthenticationError as exc:
        print("  Rejected bad password: " + str(exc))

    # Encrypted transmission demo.
    secret = "card:4111-1111-1111-1111"
    cipher = system.secure_send(secret)
    plain = system.secure_receive(cipher)
    print("  Encrypted transport: '" + cipher + "' -> decrypted matches: " + str(plain == secret))

    # 2) Restaurant + menu setup (authorized owner).
    print("\n-- Restaurant & menu setup --")
    owner_user = system.auth.require_role(owner_token, UserRole.RESTAURANT)
    diner = system.restaurants.create_restaurant(owner_user, "Bob's Diner", location=1.0)  # type: ignore[arg-type]
    burger = system.restaurants.add_menu_item(owner_user, diner.restaurant_id, "Burger", 8.50)  # type: ignore[arg-type]
    fries = system.restaurants.add_menu_item(owner_user, diner.restaurant_id, "Fries", 3.25)  # type: ignore[arg-type]
    soda = system.restaurants.add_menu_item(owner_user, diner.restaurant_id, "Soda", 1.75)  # type: ignore[arg-type]
    print("  Created '" + diner.name + "' with " + str(len(diner.menu.items)) + " menu items.")

    # 1) Customer browses nearby restaurants and views menu.
    print("\n-- Browse nearby & view menu --")
    cust_user = system.auth.authenticate(cust_token)
    nearby = system.restaurants.browse_nearby(cust_user.location, radius=5.0)  # type: ignore[arg-type]
    print("  Nearby open restaurants: " + ", ".join(r.name for r in nearby))
    for mi in system.restaurants.view_menu(diner.restaurant_id):
        print("    - " + mi.name + ": $" + format(mi.price, ".2f"))

    # Customer places a DELIVERY order.
    print("\n-- Place delivery order --")
    order = system.orders.place_order(
        cust_user,  # type: ignore[arg-type]
        diner.restaurant_id,
        {burger.item_id: 2, fries.item_id: 1, soda.item_id: 2},
        OrderType.DELIVERY,
        priority=Priority.NORMAL,
    )
    print("  Placed order " + order.order_id + " total $" + format(order.total, ".2f")
          + " status=" + order.status.value)

    # 2) Restaurant modifies (availability), then accepts.
    print("\n-- Restaurant manages order --")
    system.orders.modify_order_quantity(owner_user, order.order_id, soda.item_id, 1)  # type: ignore[arg-type]
    print("  Owner reduced soda to 1; new total $" + format(order.total, ".2f"))
    system.orders.accept_order(owner_user, order.order_id)  # type: ignore[arg-type]

    # 4) Adaptive: bump priority during a rush.
    system.orders.set_priority(order.order_id, Priority.HIGH)
    print("  Order priority is now " + order.priority.name + ".")

    system.orders.start_preparing(owner_user, order.order_id)  # type: ignore[arg-type]
    system.orders.mark_ready(owner_user, order.order_id)  # type: ignore[arg-type]
    delivery = system.deliveries.get_by_order(order.order_id)
    print("  Order ready; assigned courier; initial ETA " + str(delivery.eta_minutes) + " min.")

    # 4) Adaptive: re-route due to road closure, recompute ETA.
    print("\n-- Adaptive re-route --")
    system.deliveries.adjust_route(delivery.delivery_id, [1.0, 3.5, 2.0])
    print("  Re-routed via detour; new ETA " + str(delivery.eta_minutes) + " min.")

    # 3) Courier lifecycle: pick up, en route, deliver.
    print("\n-- Courier delivery lifecycle --")
    courier_user = system.auth.require_role(courier_token, UserRole.COURIER)
    system.orders.courier_pickup(courier_user, order.order_id)  # type: ignore[arg-type]
    system.orders.courier_out_for_delivery(courier_user, order.order_id)  # type: ignore[arg-type]
    system.orders.courier_deliver(courier_user, order.order_id)  # type: ignore[arg-type]
    print("  Order final status: " + order.status.value
          + "; delivery status: " + delivery.status.value)

    # 5) Feedback for restaurant and courier.
    print("\n-- Feedback & service quality --")
    system.feedback.submit(
        order,
        restaurant_rating=5,
        courier_id=courier_user.user_id,
        courier_rating=4,
        comment="Hot and on time.",
    )
    print("  Restaurant score: " + str(system.feedback.restaurant_score(diner.restaurant_id)))
    print("  Courier score: " + str(system.feedback.courier_score(courier_user.user_id)))

    # 6) Notifications for all parties.
    print("\n-- Notifications (per-user inboxes) --")
    _print_inbox(system, cust_user)
    _print_inbox(system, owner_user)
    _print_inbox(system, courier_user)

    # Demonstrate invalid transition handling.
    print("\n-- Domain error handling --")
    try:
        system.orders.accept_order(owner_user, order.order_id)  # type: ignore[arg-type]
    except InvalidStateTransitionError as exc:
        print("  Prevented invalid transition: " + str(exc))

    # Demonstrate a PICKUP order quickly.
    print("\n-- Pickup order flow --")
    pickup_order = system.orders.place_order(
        cust_user,  # type: ignore[arg-type]
        diner.restaurant_id,
        {burger.item_id: 1},
        OrderType.PICKUP,
    )
    system.orders.accept_order(owner_user, pickup_order.order_id)  # type: ignore[arg-type]
    system.orders.start_preparing(owner_user, pickup_order.order_id)  # type: ignore[arg-type]
    system.orders.mark_ready(owner_user, pickup_order.order_id)  # type: ignore[arg-type]
    system.orders.customer_pickup(cust_user, pickup_order.order_id)  # type: ignore[arg-type]
    print("  Pickup order " + pickup_order.order_id + " status: " + pickup_order.status.value)

    print("\n=== Demo complete ===")


if __name__ == "__main__":
    try:
        sys.stdout.reconfigure(encoding="utf-8")
    except Exception:
        pass
    main()
